		'import { CommonFlags, NodeKind } from "assemblyscript/dist/assemblyscript.js";\nimport { createParticipatingMemberHash } from "./hash.js";\nconst NON_MANAGED_CLASS_TYPE_NAMES = new Set([\n  "Array",\n  "ArrayBuffer",\n  "ArrayBufferView",\n  "ArrayLike",\n  "DataView",\n  "Date",\n  "Float32Array",\n  "Float64Array",\n  "Int8Array",\n  "Int16Array",\n  "Int32Array",\n  "Int64Array",\n  "Map",\n  "Set",\n  "StaticArray",\n  "String",\n  "Uint8Array",\n  "Uint8ClampedArray",\n  "Uint16Array",\n  "Uint32Array",\n  "Uint64Array",\n  "bool",\n  "f32",\n  "f64",\n  "i8",\n  "i16",\n  "i32",\n  "i64",\n  "isize",\n  "string",\n  "u8",\n  "u16",\n  "u32",\n  "u64",\n  "usize",\n  "v128"\n]);\nconst ARRAY_BUFFER_VIEW_TYPE_NAMES = new Set([\n  "ArrayBufferView",\n  "DataView",\n  "Float32Array",\n  "Float64Array",\n  "Int8Array",\n  "Int16Array",\n  "Int32Array",\n  "Int64Array",\n  "Uint8Array",\n  "Uint8ClampedArray",\n  "Uint16Array",\n  "Uint32Array",\n  "Uint64Array"\n]);\nfunction isParticipatingFieldDeclaration(fieldDeclaration) {\n  return (fieldDeclaration.flags & CommonFlags.Static) === 0;\n}\nfunction isParticipatingGetterDeclaration(methodDeclaration) {\n  return (methodDeclaration.flags & CommonFlags.Static) === 0 && (methodDeclaration.flags & CommonFlags.Get) !== 0 && (methodDeclaration.flags & CommonFlags.Set) === 0 && (methodDeclaration.flags & CommonFlags.Constructor) === 0;\n}\nfunction getParticipatingMemberTypeNode(declaration) {\n  if (declaration.kind === NodeKind.FieldDeclaration) {\n    return declaration.type;\n  }\n  return declaration.signature.returnType ?? null;\n}\nfunction getNamedTypeName(typeNode) {\n  if (typeNode === null || typeNode.kind !== NodeKind.NamedType) {\n    return null;\n  }\n  return typeNode.name.identifier.text;\n}\nfunction getStrictEqualityComparisonStrategy(classDeclaration, declaration, knownClassNames) {\n  const typeNode = getParticipatingMemberTypeNode(declaration);\n  const typeName = getNamedTypeName(typeNode);\n  if (typeName === null) {\n    return "value";\n  }\n  if (classDeclaration.typeParameters?.some((typeParameter) => typeParameter.name.text === typeName) ?? false) {\n    return "value";\n  }\n  if (typeName === "ArrayBuffer") {\n    return "arrayBuffer";\n  }\n  if (ARRAY_BUFFER_VIEW_TYPE_NAMES.has(typeName)) {\n    return "arrayBufferView";\n  }\n  if (typeName === "Set") {\n    return "set";\n  }\n  if (typeName === "Map") {\n    return "map";\n  }\n  if (NON_MANAGED_CLASS_TYPE_NAMES.has(typeName) || !knownClassNames.has(typeName)) {\n    return "value";\n  }\n  return "managedClass";\n}\nexport function getParticipatingInstanceMembers(classDeclaration, knownClassNames = new Set) {\n  const participatingMembers = [];\n  for (const member of classDeclaration.members) {\n    if (member.kind === NodeKind.FieldDeclaration && isParticipatingFieldDeclaration(member)) {\n      participatingMembers.push({\n        declaration: member,\n        hash: createParticipatingMemberHash("field", member.name.text),\n        kind: "field",\n        name: member.name.text,\n        strictEqualityComparisonStrategy: getStrictEqualityComparisonStrategy(classDeclaration, member, knownClassNames)\n      });\n      continue;\n    }\n    if (member.kind === NodeKind.MethodDeclaration && isParticipatingGetterDeclaration(member)) {\n      participatingMembers.push({\n        declaration: member,\n        hash: createParticipatingMemberHash("getter", member.name.text),\n        kind: "getter",\n        name: member.name.text,\n        strictEqualityComparisonStrategy: getStrictEqualityComparisonStrategy(classDeclaration, member, knownClassNames)\n      });\n    }\n  }\n  return participatingMembers;\n}\n',
